/**
 * WebSocket Binary Data Demo
 *
 * A standalone demo component that shows how binary blob data is fetched
 * through WebSocket and rendered as images. This demonstrates the core
 * pattern used by thumbnails and can be extended for full media blob sync.
 */

/* @jsxImportSource solid-js */
import { customElement } from "solid-element";
import { createSignal, onMount, onCleanup, Show, For } from "solid-js";
import { WebSocketClient, ConnectionStatus } from "../lib/websocket-client.js";
import type { MediaBlob } from "../lib/websocket-types.js";

export interface WebSocketBinaryDemoProps {
  /** WebSocket URL (default: ws://localhost:8080/ws) */
  wsUrl?: string;
  /** API base URL for fallback HTTP requests */
  apiBaseUrl?: string;
  /** Demo title */
  title?: string;
}

function WebSocketBinaryDemoComponent(props: WebSocketBinaryDemoProps) {
  const [client, setClient] = createSignal<WebSocketClient | null>(null);
  const [isConnected, setIsConnected] = createSignal(false);
  const [mediaBlobs, setMediaBlobs] = createSignal<MediaBlob[]>([]);
  const [binaryData, setBinaryData] = createSignal<Map<string, string>>(
    new Map()
  );
  const [logs, setLogs] = createSignal<string[]>([]);
  const [requestedThumbnails, setRequestedThumbnails] = createSignal<
    Set<string>
  >(new Set());

  const wsUrl = () => props.wsUrl || "ws://localhost:8080/ws";
  const title = () => props.title || "WebSocket Binary Data Demo";

  const addLog = (message: string) => {
    const timestamp = new Date().toLocaleTimeString();
    setLogs((prev) => [...prev.slice(-19), `[${timestamp}] ${message}`]);
  };

  // Helper function to create data URL from binary data array
  const createDataUrl = (data: number[], mimeType: string): string => {
    const uint8Array = new Uint8Array(data);
    const blob = new Blob([uint8Array], { type: mimeType });
    return URL.createObjectURL(blob);
  };

  const connectWebSocket = async () => {
    try {
      const wsClient = new WebSocketClient({
        url: wsUrl(),
        autoReconnect: true,
        reconnectDelay: 3000,
        maxReconnectAttempts: 5,
      });

      // Connection events
      wsClient.on("statusChange", (status) => {
        setIsConnected(status === ConnectionStatus.Connected);
        addLog(`WebSocket status: ${status}`);
      });

      // Media blobs list received
      wsClient.on("mediaBlobs", (data) => {
        setMediaBlobs(data.blobs);
        addLog(`Received ${data.blobs.length} media blobs`);
      });

      // Binary data received (this is the key part!)
      wsClient.on("mediaBlobData", (data) => {
        addLog(
          `Received binary data for ${data.id} (${data.data.length} bytes)`
        );

        // Convert binary data to blob URL
        const mimeType = data.mime || "image/webp";
        const blobUrl = createDataUrl(data.data, mimeType);

        // Store the blob URL
        setBinaryData((prev) => new Map(prev).set(data.id, blobUrl));
        addLog(
          `Created blob URL for ${data.id}: ${blobUrl.substring(0, 50)}...`
        );
      });

      // Thumbnails received (similar to binary data but specifically for thumbnails)
      wsClient.on("thumbnails", (data) => {
        addLog(`Received thumbnails for ${data.media_blob_id}`);

        // Process each thumbnail
        data.thumbnails.forEach((thumbnail) => {
          if (thumbnail.data && thumbnail.data.length > 0) {
            const mimeType = thumbnail.mime || "image/webp";
            const blobUrl = createDataUrl(thumbnail.data, mimeType);
            setBinaryData((prev) => new Map(prev).set(thumbnail.id, blobUrl));
            addLog(`Created thumbnail URL: ${thumbnail.id}`);
          }
        });
      });

      wsClient.on("error", (data) => {
        addLog(`WebSocket error: ${data.message}`);
      });

      await wsClient.connect();
      setClient(wsClient);
      addLog("WebSocket client initialized");
    } catch (error) {
      addLog(
        `Failed to connect: ${error instanceof Error ? error.message : "Unknown error"}`
      );
    }
  };

  const disconnect = () => {
    const wsClient = client();
    if (wsClient) {
      wsClient.disconnect();
      setClient(null);
      setIsConnected(false);
      addLog("Disconnected");
    }
  };

  const loadMediaBlobs = () => {
    const wsClient = client();
    if (wsClient && isConnected()) {
      wsClient.getMediaBlobs(20, 0); // Get first 20 blobs
      addLog("Requesting media blobs...");
    } else {
      addLog("Not connected to WebSocket");
    }
  };

  const requestBinaryData = (blobId: string) => {
    const wsClient = client();
    if (wsClient && isConnected()) {
      wsClient.getMediaBlobData(blobId);
      addLog(`Requesting binary data for ${blobId}...`);
    } else {
      addLog("Not connected to WebSocket");
    }
  };

  const requestThumbnails = (blobId: string) => {
    const wsClient = client();
    if (wsClient && isConnected()) {
      wsClient.getThumbnails(blobId);
      setRequestedThumbnails((prev) => new Set([...prev, blobId]));
      addLog(`Requesting thumbnails for ${blobId}...`);
    } else {
      addLog("Not connected to WebSocket");
    }
  };

  const clearLogs = () => {
    setLogs([]);
  };

  const clearBinaryData = () => {
    // Revoke all blob URLs to free memory
    binaryData().forEach((url) => URL.revokeObjectURL(url));
    setBinaryData(new Map());
    addLog("Cleared all binary data");
  };

  onMount(() => {
    addLog("Demo initialized");
  });

  onCleanup(() => {
    disconnect();
    // Clean up blob URLs
    binaryData().forEach((url) => URL.revokeObjectURL(url));
  });

  return (
    <div
      style={{
        fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif",
        padding: "20px",
        maxWidth: "1200px",
        margin: "0 auto",
        backgroundColor: "#f8fafc",
        minHeight: "100vh",
      }}
    >
      <h1
        style={{
          margin: "0 0 20px 0",
          fontSize: "24px",
          fontWeight: "700",
          color: "#1f2937",
        }}
      >
        {title()}
      </h1>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gap: "20px",
          marginBottom: "20px",
        }}
      >
        {/* Connection Controls */}
        <div
          style={{
            backgroundColor: "#ffffff",
            padding: "16px",
            borderRadius: "8px",
            border: "1px solid #e5e7eb",
          }}
        >
          <h3
            style={{ margin: "0 0 12px 0", fontSize: "16px", color: "#374151" }}
          >
            đź”Ś WebSocket Connection
          </h3>

          <div style={{ marginBottom: "12px" }}>
            <strong>URL:</strong> {wsUrl()}
          </div>

          <div style={{ marginBottom: "12px" }}>
            <strong>Status:</strong>
            <span
              style={{
                color: isConnected() ? "#059669" : "#dc2626",
                marginLeft: "8px",
              }}
            >
              {isConnected() ? "đźź˘ Connected" : "đź”´ Disconnected"}
            </span>
          </div>

          <div style={{ display: "flex", gap: "8px" }}>
            <Show when={!client()}>
              <button
                onClick={connectWebSocket}
                style={{
                  padding: "8px 16px",
                  borderRadius: "6px",
                  border: "1px solid #3b82f6",
                  backgroundColor: "#3b82f6",
                  color: "#ffffff",
                  cursor: "pointer",
                }}
              >
                Connect
              </button>
            </Show>

            <Show when={client()}>
              <button
                onClick={disconnect}
                style={{
                  padding: "8px 16px",
                  borderRadius: "6px",
                  border: "1px solid #dc2626",
                  backgroundColor: "#dc2626",
                  color: "#ffffff",
                  cursor: "pointer",
                }}
              >
                Disconnect
              </button>
            </Show>
          </div>
        </div>

        {/* Data Controls */}
        <div
          style={{
            backgroundColor: "#ffffff",
            padding: "16px",
            borderRadius: "8px",
            border: "1px solid #e5e7eb",
          }}
        >
          <h3
            style={{ margin: "0 0 12px 0", fontSize: "16px", color: "#374151" }}
          >
            đź“¦ Data Operations
          </h3>

          <div style={{ marginBottom: "12px" }}>
            <strong>Media Blobs:</strong> {mediaBlobs().length}
          </div>

          <div style={{ marginBottom: "12px" }}>
            <strong>Binary Data:</strong> {binaryData().size} items
          </div>

          <div style={{ display: "flex", gap: "8px", flexWrap: "wrap" }}>
            <button
              onClick={loadMediaBlobs}
              disabled={!isConnected()}
              style={{
                padding: "6px 12px",
                borderRadius: "4px",
                border: "1px solid #10b981",
                backgroundColor: isConnected() ? "#10b981" : "#9ca3af",
                color: "#ffffff",
                cursor: isConnected() ? "pointer" : "not-allowed",
                fontSize: "12px",
              }}
            >
              Load Blobs
            </button>

            <button
              onClick={clearBinaryData}
              style={{
                padding: "6px 12px",
                borderRadius: "4px",
                border: "1px solid #f59e0b",
                backgroundColor: "#f59e0b",
                color: "#ffffff",
                cursor: "pointer",
                fontSize: "12px",
              }}
            >
              Clear Binary
            </button>
          </div>
        </div>
      </div>

      {/* Media Blobs Grid */}
      <Show when={mediaBlobs().length > 0}>
        <div
          style={{
            backgroundColor: "#ffffff",
            padding: "16px",
            borderRadius: "8px",
            border: "1px solid #e5e7eb",
            marginBottom: "20px",
          }}
        >
          <h3
            style={{ margin: "0 0 16px 0", fontSize: "16px", color: "#374151" }}
          >
            đźŽŻ Media Blobs ({mediaBlobs().length})
          </h3>

          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fill, minmax(200px, 1fr))",
              gap: "12px",
            }}
          >
            <For each={mediaBlobs()}>
              {(blob) => {
                const hasBinaryData = () => binaryData().has(blob.id);
                const hasThumbnails = () =>
                  blob.metadata?.has_thumbnails === true;
                const isRequested = () => requestedThumbnails().has(blob.id);

                return (
                  <div
                    style={{
                      border: "1px solid #e5e7eb",
                      borderRadius: "6px",
                      padding: "12px",
                      backgroundColor: "#f9fafb",
                    }}
                  >
                    {/* Preview */}
                    <div
                      style={{
                        width: "100%",
                        height: "120px",
                        backgroundColor: "#f3f4f6",
                        borderRadius: "4px",
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        marginBottom: "8px",
                        overflow: "hidden",
                      }}
                    >
                      <Show
                        when={hasBinaryData()}
                        fallback={
                          <span style={{ fontSize: "24px", color: "#9ca3af" }}>
                            {blob.mime?.startsWith("image/")
                              ? "đź–Ľď¸Ź"
                              : blob.mime?.startsWith("audio/")
                                ? "đźŽµ"
                                : blob.mime?.startsWith("video/")
                                  ? "đźŽ¬"
                                  : "đź“„"}
                          </span>
                        }
                      >
                        <img
                          src={binaryData().get(blob.id)}
                          alt={`Binary data for ${blob.id}`}
                          style={{
                            maxWidth: "100%",
                            maxHeight: "100%",
                            objectFit: "cover",
                          }}
                          loading="lazy"
                        />
                      </Show>
                    </div>

                    {/* Info */}
                    <div
                      style={{
                        fontSize: "12px",
                        color: "#6b7280",
                        marginBottom: "8px",
                      }}
                    >
                      <div>
                        <strong>ID:</strong> {blob.id.slice(0, 8)}...
                      </div>
                      <div>
                        <strong>MIME:</strong> {blob.mime || "unknown"}
                      </div>
                      <div>
                        <strong>Size:</strong>{" "}
                        {blob.size
                          ? `${Math.round(blob.size / 1024)}KB`
                          : "unknown"}
                      </div>
                    </div>

                    {/* Status indicators */}
                    <div
                      style={{
                        display: "flex",
                        gap: "4px",
                        marginBottom: "8px",
                      }}
                    >
                      <Show when={hasThumbnails()}>
                        <span
                          style={{
                            fontSize: "10px",
                            padding: "2px 6px",
                            backgroundColor: "#dcfce7",
                            color: "#166534",
                            borderRadius: "10px",
                          }}
                        >
                          Has Thumbnails
                        </span>
                      </Show>

                      <Show when={hasBinaryData()}>
                        <span
                          style={{
                            fontSize: "10px",
                            padding: "2px 6px",
                            backgroundColor: "#dbeafe",
                            color: "#1e40af",
                            borderRadius: "10px",
                          }}
                        >
                          Binary Loaded
                        </span>
                      </Show>

                      <Show when={isRequested() && !hasBinaryData()}>
                        <span
                          style={{
                            fontSize: "10px",
                            padding: "2px 6px",
                            backgroundColor: "#fef3c7",
                            color: "#92400e",
                            borderRadius: "10px",
                          }}
                        >
                          Loading...
                        </span>
                      </Show>
                    </div>

                    {/* Action buttons */}
                    <div style={{ display: "flex", gap: "4px" }}>
                      <button
                        onClick={() => requestBinaryData(blob.id)}
                        disabled={!isConnected() || hasBinaryData()}
                        style={{
                          flex: 1,
                          padding: "4px 8px",
                          fontSize: "10px",
                          borderRadius: "4px",
                          border: "1px solid #8b5cf6",
                          backgroundColor:
                            !isConnected() || hasBinaryData()
                              ? "#e5e7eb"
                              : "#8b5cf6",
                          color:
                            !isConnected() || hasBinaryData()
                              ? "#9ca3af"
                              : "#ffffff",
                          cursor:
                            !isConnected() || hasBinaryData()
                              ? "not-allowed"
                              : "pointer",
                        }}
                      >
                        Get Binary
                      </button>

                      <Show when={hasThumbnails()}>
                        <button
                          onClick={() => requestThumbnails(blob.id)}
                          disabled={!isConnected() || isRequested()}
                          style={{
                            flex: 1,
                            padding: "4px 8px",
                            fontSize: "10px",
                            borderRadius: "4px",
                            border: "1px solid #06b6d4",
                            backgroundColor:
                              !isConnected() || isRequested()
                                ? "#e5e7eb"
                                : "#06b6d4",
                            color:
                              !isConnected() || isRequested()
                                ? "#9ca3af"
                                : "#ffffff",
                            cursor:
                              !isConnected() || isRequested()
                                ? "not-allowed"
                                : "pointer",
                          }}
                        >
                          Get Thumbnails
                        </button>
                      </Show>
                    </div>
                  </div>
                );
              }}
            </For>
          </div>
        </div>
      </Show>

      {/* Activity Log */}
      <div
        style={{
          backgroundColor: "#ffffff",
          padding: "16px",
          borderRadius: "8px",
          border: "1px solid #e5e7eb",
        }}
      >
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            marginBottom: "12px",
          }}
        >
          <h3 style={{ margin: "0", fontSize: "16px", color: "#374151" }}>
            đź“‹ Activity Log
          </h3>
          <button
            onClick={clearLogs}
            style={{
              padding: "4px 8px",
              fontSize: "12px",
              borderRadius: "4px",
              border: "1px solid #6b7280",
              backgroundColor: "#ffffff",
              color: "#6b7280",
              cursor: "pointer",
            }}
          >
            Clear
          </button>
        </div>

        <div
          style={{
            height: "200px",
            overflowY: "auto",
            backgroundColor: "#f9fafb",
            padding: "8px",
            borderRadius: "4px",
            border: "1px solid #e5e7eb",
            fontFamily: "Monaco, 'Cascadia Code', 'Roboto Mono', monospace",
            fontSize: "11px",
            lineHeight: "1.4",
          }}
        >
          <Show
            when={logs().length > 0}
            fallback={
              <div style={{ color: "#9ca3af" }}>No activity yet...</div>
            }
          >
            <For each={logs()}>
              {(log) => <div style={{ marginBottom: "2px" }}>{log}</div>}
            </For>
          </Show>
        </div>
      </div>

      {/* Instructions */}
      <div
        style={{
          backgroundColor: "#fef3c7",
          padding: "16px",
          borderRadius: "8px",
          border: "1px solid #f59e0b",
          marginTop: "20px",
        }}
      >
        <h4 style={{ margin: "0 0 8px 0", fontSize: "14px", color: "#92400e" }}>
          đź’ˇ How to use this demo:
        </h4>
        <ol
          style={{
            margin: "0",
            paddingLeft: "20px",
            fontSize: "12px",
            color: "#92400e",
          }}
        >
          <li>Click "Connect" to establish WebSocket connection</li>
          <li>Click "Load Blobs" to fetch media blobs from server</li>
          <li>
            Click "Get Binary" on any blob to download its full binary data via
            WebSocket
          </li>
          <li>Click "Get Thumbnails" on blobs that have thumbnails</li>
          <li>Watch the Activity Log to see the WebSocket messages flow</li>
          <li>Binary data is converted to blob URLs and displayed as images</li>
        </ol>
      </div>
    </div>
  );
}

// Register the web component
customElement(
  "websocket-binary-demo",
  {
    wsUrl: String,
    apiBaseUrl: String,
    title: String,
  },
  WebSocketBinaryDemoComponent
);

export default WebSocketBinaryDemoComponent;
